#include <bits/stdc++.h> 
using namespace std;
const int N=100005,mod=10007;
int n,num_l,ls[N],rs[N],val[N],dp[N][2],vis[N],cnt;
string s;
stack<int> st;
void dfs(int u)
{
	if(u==0) return ;
	dfs(ls[u]);
	dfs(rs[u]);
	if(vis[u]==2)
	{
		dp[u][0]=(dp[ls[u]][0]*dp[rs[u]][0])%mod;
		dp[u][1]=((dp[ls[u]][1]*dp[rs[u]][0])%mod+(dp[ls[u]][0]*dp[rs[u]][1])%mod+(dp[ls[u]][1]*dp[rs[u]][1])%mod)%mod;
	}
	else
	{
		dp[u][1]=(dp[ls[u]][1]*dp[rs[u]][1])%mod;
		dp[u][0]=((dp[ls[u]][1]*dp[rs[u]][0])%mod+(dp[ls[u]][0]*dp[rs[u]][1])%mod+(dp[ls[u]][0]*dp[rs[u]][0])%mod)%mod;
	}
}
int main()
{
	cin>>n>>s;
	s=" "+s;
	for(int i=1;i<=n;i++)
	{
		if(s[i]=='(') num_l++;
		else if(s[i]==')') num_l--;
		else if(s[i]=='*')
		{
			val[++cnt]=2*num_l+1;
			vis[cnt]=1;
		}
		else
		{
			val[++cnt]=2*num_l;
			vis[cnt]=2;
		}
	}
	for(int i=1;i<=cnt;i++)
	{
		int lst=0;
		while((!st.empty())&&val[st.top()]>=val[i])
		{
			lst=st.top();
			st.pop();

		}
		if(!st.empty())
		{
			rs[st.top()]=i;
		}
		if(lst)
		{
			ls[i]=lst;
		}
		st.push(i);
	}
	int root=0;
	while(!st.empty())
	{
		root=st.top();
		st.pop();
	}
	dp[0][1]=dp[0][0]=1;
	dfs(root);
	cout<<dp[root][0];
	return 0;
}
